import{c as o,Q as n,j as s,m as a}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"区块的生命:加载、ticket 等级与模拟距离","description":"","frontmatter":{},"headers":[],"relativePath":"minecraftLearning/05-区块的生命-加载ticket与模拟距离.md","filePath":"minecraftLearning/05-区块的生命-加载ticket与模拟距离.md","lastUpdated":1781674740000}'),e={name:"minecraftLearning/05-区块的生命-加载ticket与模拟距离.md"};function r(i,t,d,l,c,p){return n(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="区块的生命-加载、ticket-等级与模拟距离" tabindex="-1">区块的生命:加载、ticket 等级与模拟距离 <a class="header-anchor" href="#区块的生命-加载、ticket-等级与模拟距离" aria-label="Permalink to &quot;区块的生命:加载、ticket 等级与模拟距离&quot;">​</a></h1><p>你建了一座全自动刷怪塔,站在旁边刷刷刷出怪、掉落、收集,一切完美。然后你跑去几百格外探险,回来发现塔里空空如也——它在你离开的整段时间里<strong>根本没运转</strong>。</p><p>很多人对这件事的理解停留在&quot;区块卸载了嘛&quot;。但真相要精细得多:那座塔所在的区块<strong>很可能还加载着</strong>,它只是被降到了一个&quot;不再跑逻辑&quot;的等级。&quot;加载&quot;和&quot;运转&quot;是两回事,而 Minecraft 用一套<strong>连续的等级数值</strong>来区分它们。</p><blockquote><p>一句话先记住:<strong>区块不是&quot;加载/卸载&quot;的二元开关,而是有一个 level 数值(越小越活跃)。玩家像光源一样把周围区块&quot;照亮&quot;,离玩家越远等级越高、越不活跃。农场停摆不是因为区块没了,而是因为它的等级掉出了&quot;会 tick&quot;的范围。</strong></p></blockquote><hr><h2 id="一、区块不是开关-是一片-距离场" tabindex="-1">一、区块不是开关,是一片&quot;距离场&quot; <a class="header-anchor" href="#一、区块不是开关-是一片-距离场" aria-label="Permalink to &quot;一、区块不是开关,是一片&quot;距离场&quot;&quot;">​</a></h2><p>朴素的心智是这样的:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>区块状态 = { 已加载, 未加载 }   // 错误的二元模型</span></span></code></pre></div><p>这个模型解释不了一堆现象:为什么有的区块加载了但不刷怪?为什么离玩家近的机器跑、远的不跑,但更远的方块明明还能被命令读到?</p><p>真实模型是:每个被加载的区块带一个<strong>整数等级 <code>level</code></strong>,这个等级构成一片<strong>距离场(distance field)</strong>,本质就是一次从&quot;加载源&quot;出发的 Dijkstra/BFS 传播:</p><ul><li>玩家所在区块等级最低(最活跃);</li><li>向外<strong>每扩散一圈,等级 +1</strong>;</li><li>等级超过某个阈值,区块就&quot;还在内存里,但什么都不做&quot;。</li></ul><p>把玩家想成一盏灯,区块等级就是亮度衰减:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>等级越大 = 离玩家越远 = 越不活跃</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   44 44 44 44 44 44 44</span></span>
<span class="line"><span>   44 34 33 33 33 34 44</span></span>
<span class="line"><span>   44 33 32 31 32 33 44</span></span>
<span class="line"><span>   44 33 31 [P]31 33 44      [P] = 玩家所在区块,等级最低</span></span>
<span class="line"><span>   44 33 32 31 32 33 44</span></span>
<span class="line"><span>   44 34 33 33 33 34 44</span></span>
<span class="line"><span>   44 44 44 44 44 44 44</span></span></code></pre></div><p>这套机制在引擎里叫 <strong>ticket 系统</strong>:任何想让某区块保持活跃的东西,都往世界里放一张 <strong>ticket(加载凭证)</strong>,ticket 自带一个&quot;能把区块压到多低等级&quot;的能力,然后这个等级从 ticket 中心向外 +1 传播。<strong>玩家本身就是一张会移动的 ticket。</strong></p><hr><h2 id="二、三条等级线-从-全功能-到-仅加载" tabindex="-1">二、三条等级线:从&quot;全功能&quot;到&quot;仅加载&quot; <a class="header-anchor" href="#二、三条等级线-从-全功能-到-仅加载" aria-label="Permalink to &quot;二、三条等级线:从&quot;全功能&quot;到&quot;仅加载&quot;&quot;">​</a></h2><p>等级不是连续生效的,而是有几条<strong>关键阈值线</strong>,跨过去就掉一档能力。记住这几个数(1.18+ Java 版):</p><table tabindex="0"><thead><tr><th>等级 level</th><th>档位</th><th>这一档会发生什么</th></tr></thead><tbody><tr><td>≤ 31</td><td><strong>entity-ticking(完整)</strong></td><td>方块 random tick、流体、红石、<strong>实体 AI 和移动</strong>、刷怪——全功能</td></tr><tr><td>32–33</td><td><strong>block-ticking</strong></td><td>方块还 tick(红石、流体、随机刻可走),但<strong>实体不再 tick</strong></td></tr><tr><td>34 ~ ~44</td><td><strong>border(仅加载)</strong></td><td>区块在内存里、能被读写,但基本不做任何更新</td></tr><tr><td>&gt; 44</td><td>不加载</td><td>卸载,等级超出 ticket 影响范围</td></tr></tbody></table><p>最关键的一条线是 <strong>31 → 32</strong>:</p><ul><li><strong>≤31</strong>:实体会动、会寻路、会被刷出来。这就是俗称的&quot;区块在 ticking&quot;。</li><li><strong>≥32</strong>:实体集体冻结。掉落物不再被漏斗吸、怪不再走、村民不再干活。</li></ul><p>第二条线是 <strong>33 → 34</strong>:跨过去连方块 tick 都停了,区块沦为&quot;只是数据&quot;。</p><blockquote><p>反直觉点:一个区块可以<strong>既&quot;加载&quot;又&quot;完全不运转&quot;</strong>。<code>/forceload</code> 强制加载的区块默认就停在 border 档(约等级 34)——它保证区块在内存、能被命令和红石跨区块读取,但<strong>不会自己跑逻辑</strong>。很多人 forceload 了刷怪塔却发现还是不刷怪,就是栽在这里:加载 ≠ ticking。</p></blockquote><hr><h2 id="三、三个-距离-别再搞混" tabindex="-1">三、三个&quot;距离&quot;别再搞混 <a class="header-anchor" href="#三、三个-距离-别再搞混" aria-label="Permalink to &quot;三、三个&quot;距离&quot;别再搞混&quot;">​</a></h2><p>玩家这边有三个看起来都叫&quot;距离&quot;的概念,它们管的是完全不同的事:</p><table tabindex="0"><thead><tr><th>概念</th><th>谁设置</th><th>管什么</th><th>关键点</th></tr></thead><tbody><tr><td><strong>render distance(渲染距离)</strong></td><td>客户端</td><td>客户端<strong>画</strong>多远的区块</td><td>纯视觉,服务端逻辑不看它</td></tr><tr><td><strong>simulation distance(模拟距离)</strong></td><td>服务端</td><td>多远的区块进入 <strong>ticking(≤31)</strong></td><td>决定 random tick、实体、刷怪范围</td></tr><tr><td><strong>chunk 加载等级 / ticket level</strong></td><td>引擎内部</td><td>每个区块<strong>具体</strong>的活跃档位</td><td>上面两者最终都落到这个数值上</td></tr></tbody></table><p>实际关系:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>render distance   → 决定客户端请求/绘制多大一圈区块(看得见)</span></span>
<span class="line"><span>simulation distance → 决定多大一圈区块等级 ≤ 31(真的在跑)</span></span>
<span class="line"><span>                      ↓ 两者都通过往区块&quot;压等级&quot;来生效</span></span>
<span class="line"><span>chunk level (距离场) → 每个区块最终的档位,决定它具体能做什么</span></span></code></pre></div><p>一个常被忽略的事实:<strong>simulation distance 可以小于 render distance</strong>。你能&quot;看见&quot;远处的山(render),但那片山<strong>不在 ticking 范围</strong>(simulation),所以山里的怪不动、机器不转。看得见,不代表跑得起来。</p><hr><h2 id="四、推论-为什么远处的农场会停摆" tabindex="-1">四、推论:为什么远处的农场会停摆 <a class="header-anchor" href="#四、推论-为什么远处的农场会停摆" aria-label="Permalink to &quot;四、推论:为什么远处的农场会停摆&quot;">​</a></h2><p>现在那座刷怪塔的谜题自解了。当你跑远:</p><ol><li>你这张&quot;移动 ticket&quot;离开了塔所在区块;</li><li>塔区块失去低等级来源,等级回升;</li><li>一旦升过 <strong>31</strong>,实体停 tick——刷怪、掉落、漏斗收集全停;</li><li>再升过 <strong>33</strong>,连 random tick 都停——作物也不长了;</li><li>升过卸载阈值,区块写盘卸载。</li></ol><p>所以&quot;远处机器停摆&quot;的本质,就是<strong>它的区块等级掉出了 ticking 档</strong>。这不是 bug,是 Minecraft 控制算力的核心手段:只给玩家身边那一小圈区块花 CPU。</p><p>要让远处机器<strong>持续运转</strong>,办法只有一个——<strong>给它的区块放一张能压到 ≤31 的 ticket</strong>:</p><table tabindex="0"><thead><tr><th>手段</th><th>原理</th></tr></thead><tbody><tr><td><strong>挂机(AFK)在机器旁</strong></td><td>玩家这张移动 ticket 把周围一圈压到 entity-ticking</td></tr><tr><td><strong>出生点区块(spawn chunks)</strong></td><td>出生点周围一圈被<strong>常驻 ticket</strong>钉在 ticking,服务器开着就一直转</td></tr><tr><td><strong>传送门(下界门)</strong></td><td>激活的传送门会给两端区块放 ticket,常被用作&quot;自然的区块加载器&quot;</td></tr><tr><td><strong><code>/forceload</code></strong></td><td>注意:默认只到 <strong>border 档</strong>,要配合机制才到 ticking;别指望它单独让实体动</td></tr><tr><td><strong>第三方区块加载器 / mod</strong></td><td>显式往目标区块写 entity-ticking 级别的 ticket</td></tr></tbody></table><blockquote><p>踩坑:<strong>出生点区块</strong>是个双刃剑。它默认常驻 ticking,所以新手常把自动机器建在出生点附近&quot;图省事&quot;——确实一直转,但也意味着这些机器<strong>永远在吃服务器 CPU</strong>,哪怕全服没人在线。大型服务器反而会刻意缩小或关闭 spawn chunk 的常驻范围来省算力。</p></blockquote><hr><h2 id="五、加载本身也是分阶段、异步的" tabindex="-1">五、加载本身也是分阶段、异步的 <a class="header-anchor" href="#五、加载本身也是分阶段、异步的" aria-label="Permalink to &quot;五、加载本身也是分阶段、异步的&quot;">​</a></h2><p>最后补一层:把区块&quot;拉到某等级&quot;并不是一瞬间的事。区块从无到有要走一条<strong>异步的生成流水线</strong>,每个阶段(<code>empty → structure_starts → … → features → full</code>)都可能要等邻居区块先到某阶段才能继续(因为村庄、洞穴这种结构会跨区块)。</p><p>这条流水线跑在<strong>独立线程池</strong>上,结果再提交回主线程。所以:</p><ul><li>你高速移动(鞍马、鞘翅、传送)时会看到<strong>地形&quot;长出来&quot;有延迟</strong>——生成流水线没追上你的脚步;</li><li>一个区块要先被生成到 <code>full</code>,才谈得上被 ticket 压到 ticking 档去跑逻辑;</li><li>ticket 等级管的是&quot;已存在的区块有多活跃&quot;,生成流水线管的是&quot;区块怎么从零到 <code>full</code>&quot;——两套系统配合,但解决的是不同问题。</li></ul><hr><h2 id="六、串联" tabindex="-1">六、串联 <a class="header-anchor" href="#六、串联" aria-label="Permalink to &quot;六、串联&quot;">​</a></h2><p>把这一篇接回前后:</p><ul><li><strong>接第 02 篇(生成阶段)</strong>:那条 <code>empty → … → full</code> 的 Status 流水线,就是区块&quot;出生&quot;的过程;本篇的 ticket 等级则决定它出生后&quot;活得多积极&quot;。生成是一次性的,等级是动态的。</li><li><strong>接第 04 篇(Tick 系统)</strong>:上一篇讲的 random tick、scheduled tick、实体 tick、邻居通知,<strong>全都只在等级足够低的区块里发生</strong>。第 04 篇讲&quot;一个 tick 内做什么&quot;,本篇讲&quot;哪些区块有资格参与这个 tick&quot;。两篇合起来才是完整的&quot;世界怎么跑起来&quot;:Tick 系统是发动机,ticket 等级是油门——它决定发动机的动力分给哪几圈区块。</li></ul><p>一句话收束本篇:<strong>Minecraft 不会平等地更新整个世界,它只把算力投给玩家照亮的那一小圈。理解了 ticket 距离场,你就能解释几乎所有&quot;为什么这台机器在这里转、在那里停&quot;的现象。</strong></p>`,47)])])}const q=o(e,[["render",r]]);export{g as __pageData,q as default};
